import React, { useState } from 'react';

function App() {
  const [history, setHistory] = useState("");
  const [result, setResult] = useState(null);

  const handlePredict = async () => {
    const historyArray = history.split(',').map(Number);
    const response = await fetch('http://localhost:8000/predict', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(historyArray)
    });
    const data = await response.json();
    setResult(data);
  };

  return (
    <div style={{ padding: '40px', fontFamily: 'Arial' }}>
      <h1>ST-HybridRec Dashboard</h1>
      <p>Enter visited Place IDs (e.g., 0, 1):</p>
      <input 
        value={history} 
        onChange={(e) => setHistory(e.target.value)}
        placeholder="0, 1"
      />
      <button onClick={handlePredict}>Predict Next Stop</button>

      {result && (
        <div style={{ marginTop: '20px', border: '1px solid #ccc', padding: '15px' }}>
          <h3>Result:</h3>
          <p><strong>Next POI:</strong> {result.prediction}</p>
          <p><strong>Confidence:</strong> {(result.confidence * 100).toFixed(2)}%</p>
        </div>
      )}
    </div>
  );
}

export default App;
